39:         : partition_id(std::move(partition_id_)), min_block(min_block_), max_block(max_block_), level(level_), mutation(mutation_)
40:     {
41:     }
42: 
43:     bool operator<(const MergeTreePartInfo & rhs) const
44:     {
45:         return std::forward_as_tuple(partition_id, min_block, max_block, level, mutation)
46:             < std::forward_as_tuple(rhs.partition_id, rhs.min_block, rhs.max_block, rhs.level, rhs.mutation);
47:     }
48: 
49:     bool operator>(const MergeTreePartInfo & rhs) const
50:     {
51:         return std::forward_as_tuple(partition_id, min_block, max_block, level, mutation)
52:             > std::forward_as_tuple(rhs.partition_id, rhs.min_block, rhs.max_block, rhs.level, rhs.mutation);
53:     }
54: 
55: 
56:     bool operator==(const MergeTreePartInfo & rhs) const
57:     {
58:         return !(*this != rhs);
59:     }
60: 
61:     bool operator!=(const MergeTreePartInfo & rhs) const
62:     {
63:         return *this < rhs || rhs < *this;
64:     }
65: 
66:     /// Get block number that can be used to determine which mutations we still need to apply to this part
67:     /// (all mutations with version greater than this block number).
68:     Int64 getDataVersion() const { return mutation ? mutation : min_block; }
69: 
70:     /// True if contains rhs (this part is obtained by merging rhs with some other parts or mutating rhs)
71:     bool contains(const MergeTreePartInfo & rhs) const
72:     {
73:         /// Containing part may have equal level iff block numbers are equal (unless level is MAX_LEVEL)
74:         /// (e.g. all_0_5_2 does not contain all_0_4_2, but all_0_5_3 or all_0_4_2_9 do)
75:         bool strictly_contains_block_range = (min_block == rhs.min_block && max_block == rhs.max_block) || level > rhs.level
76:             || level == MAX_LEVEL || level == LEGACY_MAX_LEVEL;
77:         return partition_id == rhs.partition_id        /// Parts for different partitions are not merged
78:             && min_block <= rhs.min_block
79:             && max_block >= rhs.max_block
80:             && level >= rhs.level
81:             && mutation >= rhs.mutation
82:             && strictly_contains_block_range;
83:     }
